import { Container, Box, Button, Table, TableBody, TableCell, TableContainer, TableHead, TableRow, Paper, Typography, Alert } from '@mui/material';
import { useState } from 'react';
import ProductForm from './ProductForm';
import DeleteConfirm from './DeleteConfirm';

export default function AdminDashboard({ productsHook, onLogout }) {
  const { products, addProduct, updateProduct, deleteProduct, exportProducts, importProducts } = productsHook;
  const [openForm, setOpenForm] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  const [message, setMessage] = useState('');

  const handleAddProduct = () => {
    setEditingProduct(null);
    setOpenForm(true);
  };

  const handleEditProduct = (product) => {
    setEditingProduct(product);
    setOpenForm(true);
  };

  const handleSaveProduct = (formData) => {
    if (editingProduct) {
      updateProduct(editingProduct.id, formData);
      setMessage('Product updated successfully');
    } else {
      addProduct(formData);
      setMessage('Product added successfully');
    }
    setTimeout(() => setMessage(''), 3000);
  };

  const handleDeleteConfirm = (product) => {
    setDeleteConfirm(product);
  };

  const handleConfirmDelete = () => {
    deleteProduct(deleteConfirm.id);
    setDeleteConfirm(null);
    setMessage('Product deleted successfully');
    setTimeout(() => setMessage(''), 3000);
  };

  const handleExport = () => {
    exportProducts();
    setMessage('Products exported successfully');
    setTimeout(() => setMessage(''), 3000);
  };

  const handleImport = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      importProducts(file)
        .then(msg => {
          setMessage(msg);
          setTimeout(() => setMessage(''), 3000);
        })
        .catch(err => {
          setMessage(`Error: ${err}`);
          setTimeout(() => setMessage(''), 3000);
        });
    }
  };

  return (
    <Container maxWidth="lg" sx={{ paddingY: 6 }}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
        <Typography variant="h3" sx={{ fontWeight: 700 }}>
          Admin Dashboard
        </Typography>
        <Button onClick={onLogout} variant="outlined" color="error">
          Logout
        </Button>
      </Box>

      {message && <Alert severity="success" sx={{ marginBottom: 2 }}>{message}</Alert>}

      <Box sx={{ display: 'flex', gap: 2, marginBottom: 4, flexWrap: 'wrap' }}>
        <Button variant="contained" onClick={handleAddProduct}>
          + Add Product
        </Button>
        <Button variant="outlined" onClick={handleExport}>
          Export Products
        </Button>
        <label>
          <input
            type="file"
            accept=".json"
            onChange={handleImport}
            style={{ display: 'none' }}
          />
          <Button variant="outlined" component="span">
            Import Products
          </Button>
        </label>
      </Box>

      <TableContainer component={Paper}>
        <Table>
          <TableHead sx={{ backgroundColor: '#f5f5f5' }}>
            <TableRow>
              <TableCell><strong>Name</strong></TableCell>
              <TableCell><strong>Category</strong></TableCell>
              <TableCell><strong>Availability</strong></TableCell>
              <TableCell align="right"><strong>Actions</strong></TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {products.map(product => (
              <TableRow key={product.id}>
                <TableCell>{product.name}</TableCell>
                <TableCell>{product.category}</TableCell>
                <TableCell>{product.availability}</TableCell>
                <TableCell align="right">
                  <Button size="small" onClick={() => handleEditProduct(product)}>Edit</Button>
                  <Button size="small" color="error" onClick={() => handleDeleteConfirm(product)}>Delete</Button>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>

      <ProductForm
        open={openForm}
        product={editingProduct}
        onSave={handleSaveProduct}
        onCancel={() => setOpenForm(false)}
      />

      <DeleteConfirm
        open={!!deleteConfirm}
        productName={deleteConfirm?.name}
        onConfirm={handleConfirmDelete}
        onCancel={() => setDeleteConfirm(null)}
      />
    </Container>
  );
}
