import { Box, TextField, Button, Dialog, DialogTitle, DialogContent, DialogActions, Alert } from '@mui/material';
import { useState, useEffect } from 'react';

export default function ProductForm({ open, product, onSave, onCancel }) {
  const [formData, setFormData] = useState({
    name: '',
    category: '',
    description: '',
    availability: 'In Stock',
    images: [],
  });
  const [error, setError] = useState('');

  useEffect(() => {
    if (product) {
      setFormData(product);
    } else {
      setFormData({ name: '', category: '', description: '', availability: 'In Stock', images: [] });
    }
  }, [product, open]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = () => {
    if (!formData.name || !formData.category) {
      setError('Name and category are required');
      return;
    }
    onSave(formData);
    onCancel();
  };

  return (
    <Dialog open={open} onClose={onCancel} maxWidth="sm" fullWidth>
      <DialogTitle>
        {product ? 'Edit Product' : 'Add Product'}
      </DialogTitle>
      <DialogContent>
        {error && <Alert severity="error" sx={{ marginBottom: 2 }}>{error}</Alert>}
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2, marginTop: 2 }}>
          <TextField
            label="Product Name"
            name="name"
            value={formData.name}
            onChange={handleChange}
            fullWidth
            required
          />
          <TextField
            label="Category"
            name="category"
            value={formData.category}
            onChange={handleChange}
            fullWidth
            required
          />
          <TextField
            label="Description"
            name="description"
            value={formData.description}
            onChange={handleChange}
            fullWidth
            multiline
            rows={3}
          />
          <TextField
            select
            label="Availability"
            name="availability"
            value={formData.availability}
            onChange={handleChange}
            fullWidth
            SelectProps={{ native: true }}
          >
            <option value="In Stock">In Stock</option>
            <option value="Out of Stock">Out of Stock</option>
          </TextField>
        </Box>
      </DialogContent>
      <DialogActions>
        <Button onClick={onCancel}>Cancel</Button>
        <Button onClick={handleSubmit} variant="contained">
          {product ? 'Update' : 'Add'} Product
        </Button>
      </DialogActions>
    </Dialog>
  );
}
