import { useParams, useNavigate } from 'react-router-dom';
import { Container, Box, Typography, Button, Grid, Card } from '@mui/material';
import { useState } from 'react';
import ImageIcon from '@mui/icons-material/Image';

export default function ProductDetail({ productsHook }) {
  const { id } = useParams();
  const navigate = useNavigate();
  const { products } = productsHook;
  const product = products.find(p => p.id === id);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);

  if (!product) {
    return (
      <Container>
        <Typography>Product not found</Typography>
        <Button onClick={() => navigate('/')}>Back to Home</Button>
      </Container>
    );
  }

  const images = product.images || [];
  const hasCurrentImage = images[currentImageIndex];

  const relatedProducts = products
    .filter(p => p.category === product.category && p.id !== product.id)
    .slice(0, 3);

  return (
    <Container maxWidth="lg" sx={{ paddingY: 6 }}>
      <Button onClick={() => navigate('/')} sx={{ marginBottom: 3 }}>← Back to Products</Button>

      <Grid container spacing={4}>
        <Grid item xs={12} md={6}>
          {hasCurrentImage ? (
            <Box
              component="img"
              src={images[currentImageIndex]}
              alt={product.name}
              sx={{ width: '100%', borderRadius: 2, marginBottom: 2 }}
              onError={(e) => {
                if (e.target) e.target.style.display = 'none';
              }}
            />
          ) : (
            <Box sx={{ width: '100%', height: 400, backgroundColor: '#e8f5e9', borderRadius: 2, display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: 2 }}>
              <ImageIcon sx={{ fontSize: 120, color: '#a5d6a7' }} />
            </Box>
          )}
          {images.length > 1 && (
            <Box sx={{ display: 'flex', gap: 1, overflowX: 'auto' }}>
              {images.map((img, idx) => (
                <Box
                  key={idx}
                  component="img"
                  src={img}
                  alt={`${product.name} ${idx}`}
                  onClick={() => setCurrentImageIndex(idx)}
                  onError={(e) => {
                    if (e.target) e.target.style.display = 'none';
                  }}
                  sx={{
                    width: 80,
                    height: 80,
                    cursor: 'pointer',
                    border: currentImageIndex === idx ? '3px solid #2e7d32' : 'none',
                    borderRadius: 1,
                    objectFit: 'cover'
                  }}
                />
              ))}
            </Box>
          )}
        </Grid>

        <Grid item xs={12} md={6}>
          <Typography variant="h3" sx={{ fontWeight: 700, marginBottom: 2 }}>
            {product.name}
          </Typography>
          <Typography variant="h6" sx={{ color: '#2e7d32', marginBottom: 2 }}>
            {product.category}
          </Typography>
          <Typography variant="body1" sx={{ color: '#666', marginBottom: 3, lineHeight: 1.8 }}>
            {product.description}
          </Typography>

          <Box sx={{ marginBottom: 3 }}>
            <Typography variant="h6" sx={{ fontWeight: 600, marginBottom: 1 }}>
              Availability
            </Typography>
            <Typography variant="body1" sx={{ color: product.availability === 'In Stock' ? '#2e7d32' : '#d32f2f' }}>
              {product.availability}
            </Typography>
          </Box>

          {product.specifications && Object.keys(product.specifications).length > 0 && (
            <Box>
              <Typography variant="h6" sx={{ fontWeight: 600, marginBottom: 1 }}>
                Specifications
              </Typography>
              {Object.entries(product.specifications).map(([key, value]) => (
                <Typography key={key} variant="body2" sx={{ color: '#666' }}>
                  <strong>{key}:</strong> {String(value)}
                </Typography>
              ))}
            </Box>
          )}
        </Grid>
      </Grid>

      {relatedProducts.length > 0 && (
        <Box sx={{ marginTop: 8 }}>
          <Typography variant="h5" sx={{ fontWeight: 600, marginBottom: 3 }}>
            Related Products
          </Typography>
          <Grid container spacing={2}>
            {relatedProducts.map(p => (
              <Grid item xs={12} sm={6} md={4} key={p.id}>
                <Card sx={{ cursor: 'pointer' }} onClick={() => navigate(`/product/${p.id}`)}>
                  {p.images && p.images.length > 0 ? (
                    <Box
                      component="img"
                      src={p.images[0]}
                      alt={p.name}
                      sx={{ width: '100%', height: 200, objectFit: 'cover' }}
                      onError={(e) => {
                        if (e.target) e.target.style.display = 'none';
                      }}
                    />
                  ) : (
                    <Box sx={{ width: '100%', height: 200, backgroundColor: '#e8f5e9', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                      <ImageIcon sx={{ fontSize: 60, color: '#a5d6a7' }} />
                    </Box>
                  )}
                  <Box sx={{ padding: 2 }}>
                    <Typography variant="h6">{p.name}</Typography>
                  </Box>
                </Card>
              </Grid>
            ))}
          </Grid>
        </Box>
      )}
    </Container>
  );
}
