import { Container, Box, TextField, Button, Typography, Alert } from '@mui/material';
import { useState } from 'react';

export default function AdminLogin({ onAuth }) {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    const correctPassword = process.env.REACT_APP_ADMIN_PASSWORD || 'flowers123';

    if (password === correctPassword) {
      onAuth(true);
      setError('');
    } else {
      setError('Incorrect password');
      setPassword('');
    }
  };

  return (
    <Container maxWidth="sm" sx={{ paddingY: 12 }}>
      <Box sx={{ textAlign: 'center', marginBottom: 4 }}>
        <Typography variant="h3" sx={{ fontWeight: 700, marginBottom: 2 }}>
          Admin Panel
        </Typography>
        <Typography variant="body1" sx={{ color: '#666' }}>
          Enter your password to access the admin dashboard
        </Typography>
      </Box>

      {error && <Alert severity="error" sx={{ marginBottom: 2 }}>{error}</Alert>}

      <Box component="form" onSubmit={handleSubmit}>
        <TextField
          fullWidth
          type="password"
          label="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          margin="normal"
          autoFocus
        />
        <Button type="submit" variant="contained" fullWidth sx={{ marginTop: 3 }}>
          Login
        </Button>
      </Box>
    </Container>
  );
}
