// src/hooks/useProducts.js
import { useState, useEffect, useCallback } from 'react';

export const useProducts = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Load products from JSON on mount
  useEffect(() => {
    const dataUrl = `${process.env.PUBLIC_URL}/data/products.json`;
    fetch(dataUrl)
      .then(res => res.json())
      .then(data => {
        setProducts(Array.isArray(data) ? data : []);
        setLoading(false);
      })
      .catch(err => {
        setError(err.message);
        setLoading(false);
      });
  }, []);

  const getProductById = useCallback((id) => {
    return products.find(p => p.id === id);
  }, [products]);

  const addProduct = useCallback((product) => {
    setProducts(prev => [...prev, { ...product, id: product.name.toLowerCase().replace(/\s+/g, '-') }]);
  }, []);

  const updateProduct = useCallback((id, updates) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  }, []);

  const deleteProduct = useCallback((id) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  }, []);

  const exportProducts = useCallback(() => {
    const dataStr = JSON.stringify(products, null, 2);
    const dataBlob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'products.json';
    link.click();
  }, [products]);

  const importProducts = useCallback((file) => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = (e) => {
        try {
          const data = JSON.parse(e.target.result);
          if (Array.isArray(data)) {
            setProducts(data);
            resolve('Import successful');
          } else {
            reject('Invalid JSON: must be an array');
          }
        } catch (err) {
          reject(`Invalid JSON: ${err.message}`);
        }
      };
      reader.onerror = () => reject('File read error');
      reader.readAsText(file);
    });
  }, []);

  return {
    products,
    loading,
    error,
    getProductById,
    addProduct,
    updateProduct,
    deleteProduct,
    exportProducts,
    importProducts,
  };
};
