import { Container, Box, TextField, Button, Typography, Grid, Alert } from '@mui/material';
import { useState } from 'react';

export default function Contact() {
  const [formData, setFormData] = useState({ name: '', email: '', message: '' });
  const [submitted, setSubmitted] = useState(false);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const contacts = JSON.parse(localStorage.getItem('contacts') || '[]');
    contacts.push({ ...formData, timestamp: new Date().toISOString() });
    localStorage.setItem('contacts', JSON.stringify(contacts));
    setSubmitted(true);
    setFormData({ name: '', email: '', message: '' });
    setTimeout(() => setSubmitted(false), 3000);
  };

  return (
    <Container maxWidth="lg" sx={{ paddingY: 6 }}>
      <Typography variant="h3" sx={{ fontWeight: 700, marginBottom: 4, textAlign: 'center' }}>
        Contact Us
      </Typography>

      <Grid container spacing={4}>
        <Grid item xs={12} md={6}>
          {submitted && <Alert severity="success" sx={{ marginBottom: 2 }}>Message sent successfully!</Alert>}
          <Box component="form" onSubmit={handleSubmit}>
            <TextField
              fullWidth
              label="Name"
              name="name"
              value={formData.name}
              onChange={handleChange}
              required
              margin="normal"
            />
            <TextField
              fullWidth
              label="Email"
              name="email"
              type="email"
              value={formData.email}
              onChange={handleChange}
              required
              margin="normal"
            />
            <TextField
              fullWidth
              label="Message"
              name="message"
              value={formData.message}
              onChange={handleChange}
              required
              multiline
              rows={4}
              margin="normal"
            />
            <Button type="submit" variant="contained" sx={{ marginTop: 2 }}>
              Send Message
            </Button>
          </Box>
        </Grid>

        <Grid item xs={12} md={6}>
          <Typography variant="h5" sx={{ fontWeight: 600, marginBottom: 2 }}>
            Get in Touch
          </Typography>
          <Typography variant="body1" sx={{ color: '#666', marginBottom: 2 }}>
            Have questions? We'd love to hear from you. Send us a message and we'll respond as soon as possible.
          </Typography>
          <Box sx={{ marginTop: 4 }}>
            <Typography variant="h6" sx={{ fontWeight: 600, marginBottom: 1 }}>
              Email
            </Typography>
            <Typography variant="body2" sx={{ color: '#666', marginBottom: 3 }}>
              info@vishwarekhaflowers.com
            </Typography>

            <Typography variant="h6" sx={{ fontWeight: 600, marginBottom: 1 }}>
              Address
            </Typography>
            <Typography variant="body2" sx={{ color: '#666', marginBottom: 3 }}>
              123 Flower Street, Garden City
            </Typography>

            <Typography variant="h6" sx={{ fontWeight: 600, marginBottom: 1 }}>
              Phone
            </Typography>
            <Typography variant="body2" sx={{ color: '#666' }}>
              +91 XXXXXXXXXX
            </Typography>
          </Box>
        </Grid>
      </Grid>
    </Container>
  );
}
