import { useState } from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { Box } from '@mui/material';
import Navigation from './components/Navigation';
import Footer from './components/Footer';
import Home from './pages/Home';
import ProductDetail from './pages/ProductDetail';
import About from './pages/About';
import Contact from './pages/Contact';
import AdminLogin from './pages/Admin/AdminLogin';
import AdminDashboard from './pages/Admin/AdminDashboard';
import { useProducts } from './hooks/useProducts';
import './App.css';

function App() {
  const [isAdminAuth, setIsAdminAuth] = useState(false);
  const productsHook = useProducts();

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', minHeight: '100vh' }}>
      <Navigation isAdminAuth={isAdminAuth} />
      <Box sx={{ flex: 1 }}>
        <Routes>
          <Route path="/" element={<Home productsHook={productsHook} />} />
          <Route path="/product/:id" element={<ProductDetail productsHook={productsHook} />} />
          <Route path="/about" element={<About />} />
          <Route path="/contact" element={<Contact />} />
          <Route
            path="/admin"
            element={!isAdminAuth ? <AdminLogin onAuth={setIsAdminAuth} /> : <Navigate to="/admin/dashboard" />}
          />
          <Route
            path="/admin/dashboard"
            element={isAdminAuth ? <AdminDashboard productsHook={productsHook} onLogout={() => setIsAdminAuth(false)} /> : <Navigate to="/admin" />}
          />
        </Routes>
      </Box>
      <Footer />
    </Box>
  );
}

export default App;
